import torch, json
from pathlib import Path
from sklearn.metrics import f1_score, accuracy_score
import numpy as np
import torch.nn as nn
NUM_CLASSES=182
class FeatureHead(nn.Module):
    def __init__(self, dim, num_classes=182, dropout=0.0, hidden_dim=0):
        super().__init__()
        if hidden_dim and hidden_dim>0:
            self.net=nn.Sequential(nn.LayerNorm(dim), nn.Dropout(dropout), nn.Linear(dim, hidden_dim), nn.GELU(), nn.Dropout(dropout), nn.Linear(hidden_dim,num_classes))
        else:
            self.net=nn.Sequential(nn.LayerNorm(dim), nn.Dropout(dropout), nn.Linear(dim,num_classes))
    def forward(self,x): return self.net(x.float())
def strip(sd): return {k[7:] if k.startswith('module.') else k:v for k,v in sd.items()}
def find_sd(ckpt):
    for key in ['feature_head_state_dict','classifier_state_dict','feature_head_state','feature_head','head_state_dict','head','model_state_dict','state_dict']:
        obj=ckpt.get(key) if isinstance(ckpt,dict) else None
        if isinstance(obj,dict) and any(torch.is_tensor(v) for v in obj.values()):
            sd=strip(obj)
            if any(k.startswith('net.') for k in sd): return key,sd
    return None,None
def dims(sd,ckpt):
    dim=int(ckpt.get('feature_dim',0) or ckpt.get('dim',0) or 0)
    hidden=int(ckpt.get('hidden_dim',0) or 0)
    if dim<=0:
        for k,v in sd.items():
            if torch.is_tensor(v) and v.ndim==2 and k.endswith('weight'):
                dim=int(v.shape[1]); break
    if hidden<=0 and 'net.5.weight' in sd: hidden=int(sd['net.5.weight'].shape[1])
    return dim,hidden
def eval_ck(path):
    ck=torch.load(path,map_location='cpu')
    key,sd=find_sd(ck)
    meta={k:ck.get(k) for k in ['model_name','feature_model','feature_dim','hidden_dim','dropout','bias_tau','val_macro_f1','best_macro_f1'] if isinstance(ck,dict) and k in ck}
    print('\nCKPT',path,'keys',list(ck.keys())[:20] if isinstance(ck,dict) else type(ck),'sdkey',key,'meta',meta)
    if sd is None: return
    dim,hidden=dims(sd,ck); print('dim hidden',dim,hidden,'sd sample',[(k,tuple(v.shape)) for k,v in list(sd.items())[:4] if torch.is_tensor(v)])
    model_name=ck.get('model_name','openai/clip-vit-base-patch16') if isinstance(ck,dict) else 'openai/clip-vit-base-patch16'
    stem=model_name.replace('/','_').replace('-','_')
    feat=Path(f'feature_cache/val_{stem}_224_features.pt')
    lab=Path(f'feature_cache/val_{stem}_224_labels.pt')
    if not feat.exists(): print('no cache',feat); return
    x=torch.load(feat).float(); y=torch.load(lab).long()
    h=FeatureHead(dim,182,float(ck.get('dropout',0.0) or 0.0),hidden); h.load_state_dict(sd,strict=True); h.eval()
    with torch.no_grad(): logits=h(x)
    tau=float(ck.get('bias_tau',0.0) or 0.0)
    if tau!=0:
        train_lab=Path(f'feature_cache/train_{stem}_224_labels.pt')
        if train_lab.exists():
            counts=torch.bincount(torch.load(train_lab).long(),minlength=182).float()
            logp=torch.log((counts+1)/(counts.sum()+182))
            logits=logits+tau*logp
    if isinstance(ck,dict) and ck.get('class_bias') is not None:
        cb=torch.as_tensor(ck.get('class_bias')).float()
        if cb.numel()==182: logits=logits+cb.view(1,-1)
    p=logits.argmax(1).numpy(); yy=y.numpy(); labs=np.unique(yy)
    print('direct val macro',f1_score(yy,p,labels=labs,average='macro',zero_division=0),'acc',accuracy_score(yy,p),'pred uniq',len(np.unique(p)), 'top',np.bincount(p,minlength=182).argsort()[-10:][::-1].tolist())
for p in ['checkpoints_features_stable/best.pt','checkpoints_features_l/best.pt','checkpoints_calibrated/best.pt','checkpoints_combo/best.pt','checkpoints_features/best.pt']:
    if Path(p).exists(): eval_ck(p)
print('\nPREDICT feature branch lines:')
import subprocess
